// Abstract class: shared state + template method
public abstract class DataExporter
{
    protected string ConnectionString { get; } // shared state
    protected DataExporter(string cs) => ConnectionString = cs;
    public void Export() { var data = FetchData(); WriteOutput(data); }
    protected abstract IEnumerable<Row> FetchData();
    protected abstract void WriteOutput(IEnumerable<Row> rows);
}

// Interface: capability contract
public interface IExportable
{
    byte[] ToBytes();
}

public class Report : DataExporter, IExportable // both at once
{
    public Report(string cs) : base(cs) { }
    protected override IEnumerable<Row> FetchData() => /* ... */ Array.Empty<Row>();
    protected override void WriteOutput(IEnumerable<Row> rows) { /* ... */ }
    public byte[] ToBytes() => /* ... */ Array.Empty<byte>();
}

